-- Part 2: Crop Plans seed data
-- SEED: Crop Plans (998 records from CSV)
-- ============================================================
ON CONFLICT DO NOTHING;

-- ============================================================
-- VIEW: active_preparations (current year, not harvested)
-- ============================================================
CREATE OR REPLACE VIEW active_preparations AS
SELECT 
  cp.id,
  cp.cp_no,
  cp.crop_name,
  cp.field_code,
  cp.planned_plant_date,
  cp.required_ready_date,
  cp.land_prep_date,
  cp.status,
  cp.year,
  cp.area_m2,
  f.area_m2 as field_area_m2
FROM crop_plans cp
LEFT JOIN fields f ON f.field_code = cp.field_code
WHERE cp.year = EXTRACT(YEAR FROM CURRENT_DATE)
  AND cp.status NOT IN ('Harvested')
ORDER BY cp.required_ready_date NULLS LAST, cp.planned_plant_date NULLS LAST;

-- Done!
SELECT 'FOMS Schema migration completed successfully' as result;
